SELECT A.APPT_ID, P.PATIENT_NAME, D.DOCTOR_NAME, DP.DEPT_NAME, A.APPT_DATE FROM APPOINTMENT A
JOIN PATIENT P 
    ON A.PATIENT_ID = P.PATIENT_ID
JOIN DOCTOR D
    ON A.DOCTOR_ID = D.DOCTOR_ID
JOIN DEPARTMENT DP
    ON D.DEPT_ID = DP.DEPT_ID;
    
SELECT D.DOCTOR_ID, D.DOCTOR_NAME, D.SPECIALIZATION, D.CONSULT_FEE 
FROM DOCTOR D
JOIN DEPARTMENT DP
    ON DP.DEPT_ID = D.DEPT_ID
WHERE DP.DEPT_ID = D.DEPT_ID AND DP.DEPT_NAME = 'Cardiology';

