SELECT C.CUSTOMER_NAME, R.RESTAURANT_NAME, O.TOTAL_AMOUNT, O.ORDER_STATUS 
FROM ORDERS O
JOIN CUSTOMER C
    ON C.CUSTOMER_ID = O.CUSTOMER_ID
JOIN RESTAURANT R
    ON R.RESTAURANT_ID = O.RESTAURANT_ID
;

SELECT O.ORDER_ID, C.CUSTOMER_NAME, D.DELIVERY_PERSON FROM ORDERS O
JOIN CUSTOMER C
    ON C.CUSTOMER_ID = O.CUSTOMER_ID
JOIN DELIVERY D
    ON O.ORDER_ID = D.ORDER_ID
WHERE D.DELIVERY_STATUS = 'Pending';


