SELECT S.NAME, C.COURSE_TITLE, I.NAME FROM ENROLLMENT E
JOIN STUDENT S 
    ON S.STUDENT_ID = E.STUDENT_ID
JOIN COURSE C
    ON C.COURSE_ID = E.COURSE_ID
JOIN INSTRUCTOR I
    ON I.INSTRUCTOR_ID = C.INSTRUCTOR_ID;
    
SELECT C.COURSE_TITLE, C.COURSE_TITLE, I.NAME FROM COURSE C
JOIN INSTRUCTOR I
    ON I.INSTRUCTOR_ID = C.INSTRUCTOR_ID
WHERE C.SEMESTER_OFFERED = 'Fall 2025';